1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	interface QuoteStep {
14	  op: "quote";
15	  items: { type: string }[];
16	}
17	
18	interface Scenario {
19	  customer: { yearsWithMHPCO: number };
20	  steps: QuoteStep[];
21	}
22	
23	const priceQuote = (items: { type: string }[]): { premium: number } => {
24	  const policyBase = items.reduce(
25	    (sum, item) => sum + (BASE_PREMIUMS[item.type] ?? 0),
26	    0,
27	  );
28	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
29	  const premium = Math.ceil(policyBase + firstInsurance + PROCESSING_FEE);
30	  return { premium };
31	};
32	
33	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
34	  const results = scenario.steps.map((step) => priceQuote(step.items));
35	  return { results };
36	};
